function fb(a, b) { if (a) { return a; } return b; }
var code = fb($.input.code, '');
var language = fb($.input.language, 'auto-detect');
var context = fb($.input.context, '');
var focusAreas = fb($.input.focusAreas, 'bugs,security,performance,readability');

var prompt = 'You are a senior software engineer conducting a thorough code review. Analyze the following code and provide detailed feedback.\n\n';
prompt += 'LANGUAGE: ' + language + '\n';
if (context) prompt += 'CONTEXT: ' + context + '\n';
prompt += 'FOCUS AREAS: ' + focusAreas + '\n\n';
prompt += 'CODE TO REVIEW:\n```\n' + code + '\n```\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Identify bugs, logic errors, and edge cases\n';
prompt += '- Flag security vulnerabilities\n';
prompt += '- Suggest performance improvements\n';
prompt += '- Comment on code style and readability\n';
prompt += '- Provide specific, actionable suggestions with code examples\n';
prompt += '- Rate the overall code quality\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "language": "detected or specified language",\n';
prompt += '  "overallRating": "A/B/C/D/F",\n';
prompt += '  "summary": "2-3 sentence assessment",\n';
prompt += '  "issues": [\n';
prompt += '    { "severity": "critical/warning/info", "category": "bug/security/performance/style", "line": "approximate line or location", "description": "what the issue is", "suggestion": "how to fix it", "codeExample": "optional improved code snippet" }\n';
prompt += '  ],\n';
prompt += '  "strengths": ["good things about the code"],\n';
prompt += '  "improvements": ["general improvement suggestions"],\n';
prompt += '  "securityNotes": "security-specific observations",\n';
prompt += '  "testingSuggestions": ["test cases to add"]\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiReview.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, issues: [], overallRating: '?', strengths: [] }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseResponse.output;

var ratingEmoji = ':white_circle:';
var rating = (fb(ai.overallRating, '')).toUpperCase();
if (rating === 'A') ratingEmoji = ':star:';
if (rating === 'B') ratingEmoji = ':large_green_circle:';
if (rating === 'C') ratingEmoji = ':large_orange_circle:';
if (rating === 'D') ratingEmoji = ':red_circle:';
if (rating === 'F') ratingEmoji = ':no_entry:';

var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':mag: Code Review — ' + (fb(ai.language, 'Code')), emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ratingEmoji + ' *Rating: ' + rating + '*\n' + (fb(ai.summary, '')) } });
blocks.push({ type: 'divider' });

var issues = fb(ai.issues, []);
if (issues.length > 0) {
  var criticals = issues.filter(function(i) { return i.severity === 'critical'; });
  var warnings = issues.filter(function(i) { return i.severity === 'warning'; });
  var infos = issues.filter(function(i) { return i.severity === 'info'; });

  if (criticals.length > 0) {
    var critText = '*:rotating_light: Critical Issues (' + criticals.length + ')*\n';
    criticals.forEach(function(issue) {
      critText += ':red_circle: *[' + issue.category + ']* ' + issue.description + '\n';
      if (issue.line) critText += '  _Location:_ ' + issue.line + '\n';
      critText += '  _Fix:_ ' + (fb(issue.suggestion, '')) + '\n';
    });
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: critText } });
  }

  if (warnings.length > 0) {
    var warnText = '*:warning: Warnings (' + warnings.length + ')*\n';
    warnings.forEach(function(issue) {
      warnText += ':large_orange_circle: *[' + issue.category + ']* ' + issue.description + '\n';
      warnText += '  _Fix:_ ' + (fb(issue.suggestion, '')) + '\n';
    });
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: warnText } });
  }

  if (infos.length > 0) {
    var infoText = '*:information_source: Suggestions (' + infos.length + ')*\n';
    infos.forEach(function(issue) {
      infoText += ':large_blue_circle: *[' + issue.category + ']* ' + issue.description + '\n';
    });
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: infoText } });
  }
}

var strengths = fb(ai.strengths, []);
if (strengths.length > 0) {
  blocks.push({ type: 'divider' });
  var strText = '*:muscle: Strengths*\n';
  strengths.forEach(function(s) { strText += ':white_check_mark: ' + s + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: strText } });
}

if (ai.securityNotes) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':lock: *Security:* ' + ai.securityNotes }] });
}

var tests = fb(ai.testingSuggestions, []);
if (tests.length > 0) {
  var testText = '*:test_tube: Test Suggestions:* ' + tests.join(', ');
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: testText }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI + One CLI' }] });

var fallback = 'Code Review: ' + rating + ' — ' + issues.length + ' issues found';
return { blocks: blocks, fallback: fallback };
